  // ─── CanvasDrawer ────────────────────────────────────────────────────────
  'CanvasDrawer': {
    name: 'CanvasDrawer',
    extends: 'DrawerBase',
    description: 'The HTML5 2D Canvas rendering backend. Set <code>drawer: "canvas"</code> to use it explicitly. Supports rotation, compositing, and image smoothing.',
    members: [
      { name: 'canvas', type: 'HTMLCanvasElement', description: 'The backing canvas element.' },
      { name: 'context', type: 'CanvasRenderingContext2D', description: 'The 2D rendering context.' },
    ],
    methods: [
      { name: 'isSupported', returns: 'Boolean', description: 'Static. Returns true if HTML5 canvas is available (essentially always true).' },
      { name: 'getType', returns: 'String', description: 'Returns <code>"canvas"</code>.' },
      { name: 'getSupportedDataFormats', returns: 'Array.<String>', description: 'Returns <code>["context2d"]</code> — the data format this drawer consumes.' },
      { name: 'canRotate', returns: 'Boolean', description: 'Returns true — the canvas drawer handles rotation natively.' },
      { name: 'draw', returns: 'void', description: 'Renders all visible tiles for the current frame.' },
      { name: 'clear', returns: 'void', description: 'Clears the canvas to a transparent or background state.' },
      { name: 'getCanvas', returns: 'HTMLCanvasElement', description: 'Returns the backing canvas element.' },
      { name: 'getContext', returns: 'CanvasRenderingContext2D', description: 'Returns the 2D rendering context.' },
      { name: 'setImageSmoothingEnabled', returns: 'void', description: 'Sets canvas image smoothing.', params: [{ name: 'imageSmoothingEnabled', type: 'Boolean', description: 'True to smooth scaled images.' }] },
      { name: 'viewportCoordToDrawerCoord', returns: 'Point', description: 'Converts a viewport point to canvas pixel coordinates (accounts for device pixel ratio).', params: [{ name: 'point', type: 'Point', description: 'Viewport point.' }] },
      { name: 'destroy', returns: 'void', description: 'Removes the canvas element and releases resources.' },
    ],
  },

  // ─── WebGLDrawer ─────────────────────────────────────────────────────────
  'WebGLDrawer': {
    name: 'WebGLDrawer',
    extends: 'DrawerBase',
    description: 'The WebGL 1.0 rendering backend. Default drawer since v5. Set <code>drawer: "webgl"</code> to use it explicitly. Provides hardware-accelerated tile compositing.',
    members: [
      { name: 'canvas', type: 'HTMLCanvasElement', description: 'The WebGL canvas element.' },
    ],
    methods: [
      { name: 'isSupported', returns: 'Boolean', description: 'Static. Returns true if WebGL 1.0 (or 2.0) is available in the browser.' },
      { name: 'getType', returns: 'String', description: 'Returns <code>"webgl"</code>.' },
      { name: 'getSupportedDataFormats', returns: 'Array.<String>', description: 'Returns <code>["context2d"]</code> — the formats the WebGL drawer uploads from.' },
      { name: 'canRotate', returns: 'Boolean', description: 'Returns true — WebGL handles rotation via transform matrices.' },
      { name: 'isWebGL2', returns: 'Boolean', description: 'Returns true if the underlying context is WebGL 2.' },
      { name: 'isContextRecoveryEnabled', returns: 'Boolean', description: 'Returns whether automatic WebGL context-loss recovery is enabled.' },
      { name: 'setContextRecoveryEnabled', returns: 'void', description: 'Enables or disables automatic WebGL context-loss recovery.', params: [{ name: 'enabled', type: 'Boolean', description: 'True to recover on context loss.' }] },
      { name: 'setImageSmoothingEnabled', returns: 'void', description: 'Toggles image smoothing during WebGL texture sampling.', params: [{ name: 'imageSmoothingEnabled', type: 'Boolean', description: 'True to enable linear filtering.' }] },
      { name: 'setUnpackWithPremultipliedAlpha', returns: 'void', description: 'Sets whether to unpack textures with premultiplied alpha.', params: [{ name: 'value', type: 'Boolean', description: 'True to use premultiplied alpha.' }] },
      { name: 'draw', returns: 'void', description: 'Renders all visible tiles into the WebGL canvas.' },
      { name: 'viewportCoordToDrawerCoord', returns: 'Point', description: 'Converts a viewport point to WebGL canvas pixel coordinates.', params: [{ name: 'point', type: 'Point', description: 'Viewport point.' }] },
      { name: 'destroy', returns: 'void', description: 'Destroys the WebGL context and releases all GPU resources.' },
    ],
  },

  // ─── HTMLDrawer ──────────────────────────────────────────────────────────
  'HTMLDrawer': {
    name: 'HTMLDrawer',
    extends: 'DrawerBase',
    description: 'DOM-based rendering backend. Each tile is an absolutely positioned <code>&lt;img&gt;</code> element inside a container div. Set <code>drawer: "html"</code>. Useful for SVG overlays or environments without canvas.',
    members: [
      { name: 'canvas', type: 'HTMLDivElement', description: 'Container div that holds all tile <code>&lt;img&gt;</code> elements (named canvas for API compatibility).' },
    ],
    methods: [
      { name: 'isSupported', returns: 'Boolean', description: 'Static. Always returns true — HTML rendering is universally supported.' },
      { name: 'getType', returns: 'String', description: 'Returns <code>"html"</code>.' },
      { name: 'getSupportedDataFormats', returns: 'Array.<String>', description: 'Returns <code>["image", "url"]</code> — formats rendered via img elements.' },
      { name: 'canRotate', returns: 'Boolean', description: 'Returns false — HTML drawer does not handle viewport rotation.' },
      { name: 'draw', returns: 'void', description: 'Positions and displays all visible tile img elements.' },
      { name: 'clear', returns: 'void', description: 'Hides all tile elements.' },
      { name: 'setImageSmoothingEnabled', returns: 'void', description: 'Sets CSS image-rendering on the container.', params: [{ name: 'imageSmoothingEnabled', type: 'Boolean', description: 'True for smooth (bilinear) scaling.' }] },
      { name: 'destroy', returns: 'void', description: 'Removes the container div and all tile elements.' },
    ],
  },

